// =============================================
// VERIFICAR HORÁRIO COMERCIAL
// Só dispara em dias úteis, 8h-18h
// =============================================
const now = new Date();
const hora = now.getHours();
const diaSemana = now.getDay(); // 0=dom, 6=sab

// Dias úteis (seg-sex) e horário comercial (8h-18h)
if (diaSemana >= 1 && diaSemana <= 5 && hora >= 8 && hora < 18) {
  return { horarioValido: true, hora, diaSemana };
}

// Fora do horário — abortar silenciosamente
return [];

// =============================================
// EXTRAIR DADOS DO LEAD PARA O AGENTE
// =============================================
const leads = $('Buscar Lead PENDENTE').item.json;
const lead = Array.isArray(leads) ? leads[0] : leads;

return {
  leadId: lead.id,
  phone: lead.telefone,
  remoteJid: lead.telefone + '@s.whatsapp.net',
  nome_contato: lead.nome_contato || '',
  nome_empresa: lead.nome_empresa || '',
  segmento: lead.segmento || 'servicos',
  cidade: lead.cidade || '',
  origem: lead.origem || '',
  observacao: lead.observacao || '',
  isFirstContact: true
};

