const text = $json.output || '';
const textLength = text.length;
const waitTime = Math.floor((textLength / 35) + (Math.random() * (4 - 2) + 2));

return {
  waitTimeSeconds: waitTime,
  responseText: text,
  phone: $('Extrair Dados Lead').item.json.phone,
  remoteJid: $('Extrair Dados Lead').item.json.remoteJid,
